import './Radio.scss';

import { Icons } from '@beeline/design-tokens/js/iconfont/icons';
import React, { useState } from 'react';

import { classNames } from '../../helpers/classnames';
import { Icon } from '../Icon';
import { Typography } from '../Typography';
import type { RadioProps } from './Radio.types';

export const Radio = React.forwardRef<HTMLInputElement, RadioProps>(
	(
		{ checked, label, disabled, error = false, className, name, dataTestId = 'Radio', onFocus, onBlur, ...props },
		ref,
	) => {
		const [isFocused, setIsFocused] = useState(false);

		const handleFocus = (event: React.FocusEvent<HTMLInputElement>) => {
			onFocus?.(event);
			setIsFocused(true);
		};

		const handleBlur = (event: React.FocusEvent<HTMLInputElement>) => {
			onBlur?.(event);
			setIsFocused(false);
		};

		return (
			<label
				data-testid={dataTestId}
				className={classNames(
					'dsb_radio',
					disabled && 'dsb_radio__disabled',
					isFocused && 'dsb_radio__focused',
					error && 'dsb_radio__error',
					className,
				)}
			>
				<span className="dsb_radio-root">
					<input
						type="radio"
						checked={checked}
						disabled={disabled}
						name={name}
						aria-invalid={error}
						className="dsb_radio-input"
						{...props}
						onFocus={handleFocus}
						onBlur={handleBlur}
						ref={ref}
					/>
					<Icon className="dsb_radio-icon" size="large" iconName={Icons.Dot} />
				</span>

				{label && (
					<>
						{typeof label === 'string' ? (
							<Typography variant="body2" className="dsb_radio-label">
								{label}
							</Typography>
						) : (
							label
						)}
					</>
				)}
			</label>
		);
	},
);
